#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int count = 0;
        for (int i = 1; i < N; i++) {
            if (A[i] == A[i-1]) {
                count++;
            }
        }
        printf("%d\n", count);
        free(A);
    }
    return 0;
}

